package com.me.cmitems.blocks.tnts.arrowtnt;

import net.fabricmc.fabric.api.client.item.v1.ItemTooltipCallback;
import net.minecraft.block.*;
import net.minecraft.entity.Entity;
import net.minecraft.entity.LivingEntity;
import net.minecraft.entity.player.PlayerEntity;
import net.minecraft.entity.projectile.ProjectileEntity;
import net.minecraft.item.Item;
import net.minecraft.item.ItemStack;
import net.minecraft.item.Items;
import net.minecraft.server.world.ServerWorld;
import net.minecraft.sound.BlockSoundGroup;
import com.me.cmitems.creator.ModBlocks;
import net.minecraft.sound.SoundCategory;
import net.minecraft.sound.SoundEvents;
import net.minecraft.stat.Stats;
import net.minecraft.text.Text;
import net.minecraft.util.ActionResult;
import net.minecraft.util.Hand;
import net.minecraft.util.hit.BlockHitResult;
import net.minecraft.util.math.BlockPos;
import net.minecraft.util.math.Direction;
import net.minecraft.world.GameRules;
import net.minecraft.world.World;
import net.minecraft.world.event.GameEvent;
import net.minecraft.world.explosion.Explosion;
import org.jetbrains.annotations.Nullable;

// Tnt that spawns arrow everywhere when explode
public class ArrowTnt extends TntBlock {
    public static final Block ARROW_TNT = ModBlocks.register(
            "arrow_tnt",
            ArrowTnt::new,
            AbstractBlock.Settings.create().sounds(BlockSoundGroup.GRASS),
            true
    );

    public ArrowTnt(Settings settings) {
        super(settings);
    }

    public static void register() {
        System.out.println("Registered Arrow TnT");
        ItemTooltipCallback.EVENT.register((stack, tooltipContext, tooltipType, list) -> {
            if (getBlockFromItem(stack.getItem()) == ARROW_TNT) {
                list.add(Text.translatable("item.cmitems.arrow_tnt.tooltip"));
            }
        });
    }

    @Override
    protected void onBlockAdded(BlockState state, World world, BlockPos pos, BlockState oldState, boolean notify) {
        if (!oldState.isOf(state.getBlock())) {
            world.scheduleBlockTick(pos, this, 1);
            if (world.isReceivingRedstonePower(pos) && primeTnt(world, pos)) {
                world.removeBlock(pos, false);
            }
        }
    }

    @Override
    protected void scheduledTick(BlockState state, ServerWorld world, BlockPos pos, net.minecraft.util.math.random.Random random) {
        for (Direction direction : Direction.values()) {
            BlockPos offset = pos.offset(direction);
            if (world.getBlockState(offset).isOf(Blocks.FIRE)) {
                if (random.nextInt(50) == 0 && primeTnt(world, pos)) { // 1 in 50 chance of igniting every tick
                    world.removeBlock(pos, false);
                    return;
                }
            }
        }

        world.scheduleBlockTick(pos, this, 1);
    }

    @Override
    public BlockState onBreak(World world, BlockPos pos, BlockState state, PlayerEntity player) {
        if (!world.isClient() && !player.getAbilities().creativeMode && (Boolean)state.get(UNSTABLE)) {
            primeTnt(world, pos);
        }

        return super.onBreak(world, pos, state, player);
    }

    @Override
    protected ActionResult onUseWithItem(ItemStack stack, BlockState state, World world, BlockPos pos, PlayerEntity player, Hand hand, BlockHitResult hit) {
        if (!stack.isOf(Items.FLINT_AND_STEEL) && !stack.isOf(Items.FIRE_CHARGE)) {
            return super.onUseWithItem(stack, state, world, pos, player, hand, hit);
        } else {
            if (primeTnt(world, pos, player)) {
                world.setBlockState(pos, Blocks.AIR.getDefaultState(), 11);
                Item item = stack.getItem();
                if (stack.isOf(Items.FLINT_AND_STEEL)) {
                    stack.damage(1, player, LivingEntity.getSlotForHand(hand));
                } else {
                    stack.decrementUnlessCreative(1, player);
                }

                player.incrementStat(Stats.USED.getOrCreateStat(item));
            } else if (world instanceof ServerWorld) {
                ServerWorld serverWorld = (ServerWorld)world;
                if (!serverWorld.getGameRules().getBoolean(GameRules.TNT_EXPLODES)) {
                    player.sendMessage(Text.translatable("block.minecraft.tnt.disabled"), true);
                    return ActionResult.PASS;
                }
            }

            return ActionResult.SUCCESS;
        }
    }

    @Override
    public void onDestroyedByExplosion(ServerWorld world, BlockPos pos, Explosion explosion) {
        if (world.getGameRules().getBoolean(GameRules.TNT_EXPLODES)) {
            ArrowTntEntity atEntity = new ArrowTntEntity(world, (double) pos.getX() + 0.5, (double) pos.getY(), (double) pos.getZ() + 0.5, explosion.getCausingEntity(), true, false);
            int i = atEntity.getFuse();
            atEntity.setFuse((short)(world.random.nextInt(i / 4) + i / 8));
            world.spawnEntity(atEntity);
        }
    }

    @Override
    protected void onProjectileHit(World world, BlockState state, BlockHitResult hit, ProjectileEntity projectile) {
        if (world instanceof ServerWorld serverWorld) {
            BlockPos blockPos = hit.getBlockPos();
            Entity entity = projectile.getOwner();
            if (projectile.isOnFire() && projectile.canModifyAt(serverWorld, blockPos) && primeTnt(world, blockPos, entity instanceof LivingEntity ? (LivingEntity)entity : null)) {
                world.removeBlock(blockPos, false);
            }
        }
    }

    public static boolean primeTnt(World world, BlockPos pos) {
        return primeTnt(world, pos, (LivingEntity) null);
    }

    private static boolean primeTnt(World world, BlockPos pos, @Nullable LivingEntity igniter) {
        if (world instanceof ServerWorld serverWorld) {
            if (serverWorld.getGameRules().getBoolean(GameRules.TNT_EXPLODES)) {
                ArrowTntEntity atEntity = new ArrowTntEntity(world, (double) pos.getX() + 0.5, (double) pos.getY(), (double) pos.getZ() + 0.5, igniter, true, false);
                world.spawnEntity(atEntity);
                world.playSound((Entity) null, pos.getX(), pos.getY(), pos.getZ(), SoundEvents.ENTITY_TNT_PRIMED, SoundCategory.BLOCKS, 1.0F, 1.0F);
                world.emitGameEvent(igniter, GameEvent.PRIME_FUSE, pos);
                return true;
            }
        }

        return false;
    }
}

package com.me.cmitems.blocks.tnts.arrowtnt;

import com.me.cmitems.creator.ModEntity;
import net.minecraft.block.BlockState;
import net.minecraft.block.Blocks;
import net.minecraft.entity.*;
import net.minecraft.entity.projectile.ArrowEntity;
import net.minecraft.fluid.FluidState;
import net.minecraft.item.ItemStack;
import net.minecraft.item.Items;
import net.minecraft.particle.ParticleTypes;
import net.minecraft.server.world.ServerWorld;
import net.minecraft.util.math.BlockPos;
import net.minecraft.world.BlockView;
import net.minecraft.world.GameRules;
import net.minecraft.world.World;
import net.minecraft.world.explosion.Explosion;
import net.minecraft.world.explosion.ExplosionBehavior;
import org.jetbrains.annotations.Nullable;

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

import static com.me.cmitems.CmItems.mc;

public class ArrowTntEntity extends TntEntity {

    public static final EntityType<ArrowTntEntity> ARROW_TNT_TYPE = ModEntity.register(
            "arrow_tnt_entity",
            ArrowTntEntity::new,
            SpawnGroup.MISC,
            1f,
            1f
    );

    private static boolean ShouldBeBurningArrows = true;
    private static boolean ShouldHaveGravity = true;

    private static final short DEFAULT_FUSE = 80;
    private static final float DEFAULT_EXPLOSION_POWER = 4.0F;
    private static final BlockState DEFAULT_BLOCK_STATE = ArrowTnt.ARROW_TNT.getDefaultState();
    private static final String BLOCK_STATE_NBT_KEY = "block_state";
    public static final String FUSE_NBT_KEY = "fuse";
    private static final String EXPLOSION_POWER_NBT_KEY = "explosion_power";
    private static final ExplosionBehavior TELEPORTED_EXPLOSION_BEHAVIOR = new ExplosionBehavior() {
        @Override
        public boolean canDestroyBlock(Explosion explosion, BlockView world, BlockPos pos, BlockState state, float power) {
            return false;
        }

        @Override
        public Optional<Float> getBlastResistance(Explosion explosion, BlockView world, BlockPos pos, BlockState blockState, FluidState fluidState) {
            return blockState.isOf(Blocks.NETHER_PORTAL) ? Optional.empty() : super.getBlastResistance(explosion, world, pos, blockState, fluidState);
        }
    };

    @Nullable
    private LivingEntity causingEntity;
    private boolean teleported;
    private float explosionPower;

    public ArrowTntEntity(EntityType<? extends TntEntity> entityType, World world) {
        super(entityType, world);
        this.explosionPower = 4.0F;
        this.intersectionChecked = true;
        this.setBlockState(DEFAULT_BLOCK_STATE);
    }

    public ArrowTntEntity(World world, double x, double y, double z, @Nullable LivingEntity igniter) {
        this(ARROW_TNT_TYPE, world);
        this.setPosition(x, y, z);
        double d = world.random.nextDouble() * 6.2831854820251465;
        this.setVelocity(-Math.sin(d) * 0.02, 0.20000000298023224, -Math.cos(d) * 0.02);
        this.setFuse(80);
        this.lastX = x;
        this.lastY = y;
        this.lastZ = z;
        this.causingEntity = igniter;
    }

    public ArrowTntEntity(World world, double x, double y, double z, @Nullable LivingEntity igniter, boolean burn, boolean gravity) {
        this(ARROW_TNT_TYPE, world);
        ShouldBeBurningArrows = burn;
        ShouldHaveGravity = gravity;
        this.setPosition(x, y, z);
        double d = world.random.nextDouble() * 6.2831854820251465;
        double dx = gravity ? -Math.sin(d) * 0.02 : 0;
        double dy = gravity ? 0.20000000298023224 : 0.20000000298023224 / 2;
        double dz = gravity ? -Math.cos(d) * 0.02 : 0;
        this.setVelocity(dx, dy, dz);
        this.setFuse(80);
        this.lastX = x;
        this.lastY = y;
        this.lastZ = z;
        this.causingEntity = igniter;

    }

    @Override
    protected double getGravity() {
        return ShouldHaveGravity ? 0.04 : 0.0;
    }

    @Override
    protected void applyGravity() {
        if (!ShouldHaveGravity) return;
        double d = this.getFinalGravity();
        if (d != 0.0) {
            this.setVelocity(this.getVelocity().add(0.0, -d, 0.0));
        }

    }

    @Override
    public void tick() {
        this.tickPortalTeleportation();
        this.applyGravity();
        this.move(MovementType.SELF, this.getVelocity());
        this.tickBlockCollision();
        if (ShouldHaveGravity) this.setVelocity(this.getVelocity().multiply(0.98));
        if (this.isOnGround() && ShouldHaveGravity) {
            this.setVelocity(this.getVelocity().multiply(0.7, -0.5, 0.7));
        }

        int i = this.getFuse() - 1;
        this.setFuse(i);
        if (i <= 0) {
            this.discard();
            if (!this.getWorld().isClient) {
                this.explode();
            }
        } else {
            this.updateWaterState();
            if (this.getWorld().isClient) {
                this.getWorld().addParticleClient(ParticleTypes.SMOKE, this.getX(), this.getY() + 0.5, this.getZ(), 0.0, 0.0, 0.0);
            }
        }
    }

    private void explode() {
        World world = this.getWorld();
        if (world instanceof ServerWorld serverWorld) {
            if (serverWorld.getGameRules().getBoolean(GameRules.TNT_EXPLODES)) {

                for (ArrowEntity arrow : this.getArrows(world)) {
                    world.spawnEntity(arrow);
                }
            }
        }
    }

    /**
     * Spawns arrows in a spherical pattern around the TNT explosion point, flying outward in all directions.
     */
    private List<ArrowEntity> getArrows(World world) {
        List<ArrowEntity> arrows = new ArrayList<>();
        if (mc.player == null) return arrows;

        int horizontalSteps = 18;
        int verticalSteps = 20;   // 18 * 20 = 360 arrows
        double radius = 1.5;      // Spawn distance from center
        double speed = 1.2;

        for (int i = 0; i < verticalSteps; i++) {
            double phi = Math.PI * (double) i / (verticalSteps - 1);

            for (int j = 0; j < horizontalSteps; j++) {
                double theta = 2.0 * Math.PI * (double) j / horizontalSteps;

                // Calculate directional vectors
                double vx = Math.sin(phi) * Math.cos(theta);
                double vy = Math.cos(phi);
                double vz = Math.sin(phi) * Math.sin(theta);

                // Calculate exact spawn position
                double x = this.getX() + vx * radius;
                double y = this.getY() + vy * radius + 0.5;
                double z = this.getZ() + vz * radius;

                // --- COLLISION TEST ---
                BlockPos spawnPos = new BlockPos((int)x, (int)y, (int)z);
                // Check if the block at the spawn position is air or non-solid
                if (!world.getBlockState(spawnPos).isAir()) {
                    continue; // Skip this arrow if it's inside a block
                }

                ArrowEntity arrow = new ArrowEntity(world, mc.player, new ItemStack(Items.ARROW), null);
                arrow.setPos(x, y, z);
                arrow.setVelocity(vx * speed, vy * speed, vz * speed);
                arrow.setOnFireFor(ShouldBeBurningArrows ? 15 : 0); // 15s of fire if should burn
                arrow.setDamage(5); // 2.5 hearts of damage

                arrows.add(arrow);
            }
        }
        return arrows;
    }

}

package com.me.cmitems.blocks.tnts.arrowtnt;

import net.fabricmc.api.EnvType;
import net.fabricmc.api.Environment;
import net.fabricmc.fabric.api.client.rendering.v1.EntityRendererRegistry;
import net.minecraft.client.render.VertexConsumerProvider;
import net.minecraft.client.render.block.BlockRenderManager;
import net.minecraft.client.render.entity.EntityRenderer;
import net.minecraft.client.render.entity.EntityRendererFactory;
import net.minecraft.client.render.entity.TntMinecartEntityRenderer;
import net.minecraft.client.render.entity.state.TntEntityRenderState;
import net.minecraft.client.util.math.MatrixStack;
import net.minecraft.util.math.MathHelper;
import net.minecraft.util.math.RotationAxis;

@Environment(EnvType.CLIENT)
public class ArrowTntEntityRenderer extends EntityRenderer<ArrowTntEntity, TntEntityRenderState> {
    private final BlockRenderManager blockRenderManager;

    public static void register() {
        EntityRendererRegistry.register(ArrowTntEntity.ARROW_TNT_TYPE, ArrowTntEntityRenderer::new);
    }

    public ArrowTntEntityRenderer(EntityRendererFactory.Context context) {
        super(context);
        this.shadowRadius = 0.5F;
        this.blockRenderManager = context.getBlockRenderManager();
    }

    @Override
    public void render(TntEntityRenderState tntEntityRenderState, MatrixStack matrixStack, VertexConsumerProvider vertexConsumerProvider, int i) {
        matrixStack.push();
        matrixStack.translate(0.0F, 0.5F, 0.0F);
        float f = tntEntityRenderState.fuse;

        if (f < 10.0F) {
            float g = 1.0F - f / 10.0F;
            g = MathHelper.clamp(g, 0.0F, 1.0F);
            g *= g;
            g *= g;
            float h = 1.0F + g * 0.3F;
            matrixStack.scale(h, h, h);
        }

        matrixStack.multiply(RotationAxis.POSITIVE_Y.rotationDegrees(-90.0F));
        matrixStack.translate(-0.5F, -0.5F, 0.5F);
        matrixStack.multiply(RotationAxis.POSITIVE_Y.rotationDegrees(90.0F));

        if (tntEntityRenderState.blockState != null) {
            TntMinecartEntityRenderer.renderFlashingBlock(
                    this.blockRenderManager,
                    tntEntityRenderState.blockState,
                    matrixStack,
                    vertexConsumerProvider,
                    i,
                    (int)f / 5 % 2 == 0
            );
        }

        matrixStack.pop();
        super.render(tntEntityRenderState, matrixStack, vertexConsumerProvider, i);
    }

    @Override
    public TntEntityRenderState createRenderState() {
        return new TntEntityRenderState();
    }

    @Override
    public void updateRenderState(ArrowTntEntity arrowTntEntity, TntEntityRenderState tntEntityRenderState, float f) {
        super.updateRenderState(arrowTntEntity, tntEntityRenderState, f);
        tntEntityRenderState.fuse = (float)arrowTntEntity.getFuse() - f + 1.0F;
        tntEntityRenderState.blockState = arrowTntEntity.getBlockState();
    }
}

